previewCss:
.darma-loader-darma-custom-646 {color: var(--loader-color, #f8fafc);
  --loader-secondary-color: var(--loader-secondary-color, #94a3b8);
  --loader-bg: var(--loader-bg, #111827);

  display: block;
  width: 84px;
  height: 84px;
  position: relative;
}

.darma-loader-darma-custom-646:before , .darma-loader-darma-custom-646:after {
  content: "";
  position: absolute;
  left: 50%;
  bottom: 0;
  width: 64px;
  height: 64px;
  border-radius: 50%;
  background: currentColor;
  transform: translate(-50% , -100%)  scale(0);
  animation: darma-loader-darma-custom-646-push_401 2s infinite linear;
}

.darma-loader-darma-custom-646:after {
  animation-delay: 1s;
}

@keyframes darma-loader-darma-custom-646-push_401 {
  0% , 50% {
    transform: translate(-50% , 0%)  scale(1)
  }

  100% {
    transform: translate(-50%, -100%) scale(0)
  }
}

